/**
 * OnboardingProgress — 3-step progression indicator for first session.
 * Creates forward momentum: Explore → Understand → Validate
 * Tracks progress via localStorage and updates dynamically.
 */
import { useState, useEffect, useCallback } from 'react';
import { tokens } from '../styles/tokens';

const T = {
  surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, blue: tokens.color.blue, amber: tokens.color.amber,
  mono: tokens.font.mono,
};

const STORAGE_KEY = 'aura_onboarding_progress';
const DISMISS_KEY = 'aura_onboarding_progress_dismissed';

const STEPS = [
  { id: 'explore', label: 'Explore', desc: 'Browse strategies', icon: '🔍' },
  { id: 'understand', label: 'Understand', desc: 'View strategy detail', icon: '💡' },
  { id: 'validate', label: 'Validate', desc: 'See validation metrics', icon: '✓' },
];

function getProgress() {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY) || '{}'); } catch { return {}; }
}

export function markStep(step) {
  const p = getProgress();
  if (!p[step]) {
    p[step] = Date.now();
    localStorage.setItem(STORAGE_KEY, JSON.stringify(p));
  }
  // Check activation
  if (p.explore && p.understand && p.validate) {
    localStorage.setItem('aura_activation_complete', '1');
  }
}

export function isActivated() {
  return localStorage.getItem('aura_activation_complete') === '1';
}

export function getStrategyViewCount() {
  try { return parseInt(localStorage.getItem('aura_strategy_views') || '0', 10); } catch { return 0; }
}

export function incrementStrategyViews() {
  const count = getStrategyViewCount() + 1;
  localStorage.setItem('aura_strategy_views', String(count));
  return count;
}

export default function OnboardingProgress() {
  const [progress, setProgress] = useState(getProgress());
  const [dismissed, setDismissed] = useState(
    localStorage.getItem(DISMISS_KEY) === '1' || isActivated()
  );

  useEffect(() => {
    const iv = setInterval(() => setProgress(getProgress()), 2000);
    return () => clearInterval(iv);
  }, []);

  if (dismissed) return null;

  const completedCount = STEPS.filter(s => progress[s.id]).length;
  if (completedCount === 3) {
    // Auto-dismiss after all steps done
    setTimeout(() => { localStorage.setItem(DISMISS_KEY, '1'); setDismissed(true); }, 3000);
  }

  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 4,
      padding: '6px 14px', background: T.surface, borderRadius: 10,
      border: `1px solid ${T.border}`, marginBottom: 12,
    }}>
      <span style={{ fontSize: 10, fontFamily: T.mono, color: T.textSec, marginRight: 8, fontWeight: 600 }}>GETTING STARTED</span>
      {STEPS.map((step, i) => {
        const done = !!progress[step.id];
        const active = !done && (i === 0 || progress[STEPS[i - 1].id]);
        return (
          <div key={step.id} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            {i > 0 && <span style={{ color: T.border, fontSize: 10, margin: '0 2px' }}>→</span>}
            <div style={{
              display: 'flex', alignItems: 'center', gap: 4,
              padding: '3px 10px', borderRadius: 6,
              background: done ? `${T.green}15` : active ? `${T.blue}10` : 'transparent',
              border: `1px solid ${done ? T.green + '33' : active ? T.blue + '22' : T.border + '44'}`,
            }}>
              <span style={{ fontSize: 10 }}>{done ? '✓' : step.icon}</span>
              <span style={{
                fontSize: 10, fontFamily: T.mono, fontWeight: 600,
                color: done ? T.green : active ? T.blue : T.textSec,
              }}>{step.label}</span>
            </div>
          </div>
        );
      })}
      {completedCount === 3 && (
        <span style={{ fontSize: 10, fontFamily: T.mono, color: T.green, marginLeft: 8, fontWeight: 700 }}>Complete!</span>
      )}
    </div>
  );
}
