/**
 * ShareStrategyModal — Branded strategy card share modal.
 * Copy link, copy card preview, share to social.
 */
import { useState, useRef, useCallback } from 'react';
import { tokens } from '../styles/tokens';

const T = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, blue: tokens.color.blue, amber: tokens.color.amber, purple: tokens.color.purple,
  mono: tokens.font.mono,
};

function MetricPill({ label, value, color }) {
  return (
    <div style={{ textAlign: 'center', padding: '6px 0' }}>
      <div style={{ fontSize: 18, fontWeight: 700, fontFamily: T.mono, color }}>{value}</div>
      <div style={{ fontSize: 10, color: T.textSec, marginTop: 4 }}>{label}</div>
    </div>
  );
}

export default function ShareStrategyModal({ strategy, onClose }) {
  const [copied, setCopied] = useState('');
  const cardRef = useRef(null);

  if (!strategy) return null;

  const shareUrl = `${window.location.origin}/s/${strategy.strategy_root_id || strategy.strategy_version_id || ''}`;
  const title = strategy.title || strategy.strategy_name || strategy.strategy_id || '';
  const alpha = (strategy.alpha_score || 0).toFixed(2);
  const sharpe = (strategy.sharpe || strategy.performance?.sharpe || 0).toFixed(2);
  const stability = (strategy.regime_stability_score || 0).toFixed(2);
  const family = strategy.family || '';
  const direction = strategy.direction || 'long';

  const copyLink = useCallback(() => {
    navigator.clipboard.writeText(shareUrl).then(() => { setCopied('link'); setTimeout(() => setCopied(''), 2000); });
  }, [shareUrl]);

  const copyCard = useCallback(async () => {
    // Copy card as text (image generation would need canvas/html2canvas)
    const text = `${title}\n\nAlpha: ${alpha} | Sharpe: ${sharpe} | Stability: ${stability}\n${family} · ${direction}\n\nView on Aura Alpha: ${shareUrl}`;
    navigator.clipboard.writeText(text).then(() => { setCopied('card'); setTimeout(() => setCopied(''), 2000); });
  }, [title, alpha, sharpe, stability, family, direction, shareUrl]);

  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.75)', zIndex: 2000, display: 'flex', justifyContent: 'center', alignItems: 'center' }}
      onClick={onClose}>
      <div style={{ background: T.surface, borderRadius: 14, width: '90%', maxWidth: 420, padding: 0, overflow: 'hidden' }}
        onClick={e => e.stopPropagation()}>

        {/* Card preview */}
        <div ref={cardRef} style={{
          background: `linear-gradient(135deg, ${T.bg}, ${T.surface})`,
          padding: '24px 28px', borderBottom: `1px solid ${T.border}`,
        }}>
          <div style={{ fontSize: 10, fontFamily: T.mono, color: T.blue, marginBottom: 8, letterSpacing: '0.06em', fontWeight: 600 }}>
            AURA ALPHA
          </div>
          <div style={{ fontSize: 22, fontWeight: 700, fontFamily: T.mono, color: T.text, marginBottom: 4 }}>
            {title}
          </div>
          <div style={{ fontSize: 11, color: T.textSec, fontFamily: T.mono, marginBottom: 16 }}>
            {family} · {direction}
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 8 }}>
            <MetricPill label="Alpha Score" value={alpha} color={parseFloat(alpha) >= 0.7 ? T.green : T.text} />
            <MetricPill label="Sharpe" value={sharpe} color={parseFloat(sharpe) >= 1.5 ? T.green : T.text} />
            <MetricPill label="Stability" value={stability} color={parseFloat(stability) >= 0.7 ? T.blue : T.text} />
          </div>
          {strategy.summary && (
            <div style={{ fontSize: 11, color: T.textSec, marginTop: 12, lineHeight: 1.5, maxHeight: 44, overflow: 'hidden' }}>
              {strategy.summary}
            </div>
          )}
        </div>

        {/* Actions */}
        <div style={{ padding: '16px 28px', display: 'flex', flexDirection: 'column', gap: 8 }}>
          <button onClick={copyLink} style={{
            width: '100%', padding: '10px 0', borderRadius: 10, fontSize: 13, fontFamily: T.mono, fontWeight: 700,
            background: copied === 'link' ? T.green + '22' : T.blue + '15',
            border: `1px solid ${copied === 'link' ? T.green : T.blue}44`,
            color: copied === 'link' ? T.green : T.blue, cursor: 'pointer',
          }}>
            {copied === 'link' ? '✓ Link Copied!' : 'Copy Strategy Link'}
          </button>
          <button onClick={copyCard} style={{
            width: '100%', padding: '10px 0', borderRadius: 10, fontSize: 13, fontFamily: T.mono, fontWeight: 600,
            background: copied === 'card' ? T.green + '22' : T.surface2,
            border: `1px solid ${copied === 'card' ? T.green : T.border}`,
            color: copied === 'card' ? T.green : T.text, cursor: 'pointer',
          }}>
            {copied === 'card' ? '✓ Card Copied!' : 'Copy Card Preview'}
          </button>
          <button onClick={onClose} style={{
            width: '100%', padding: '8px 0', borderRadius: 10, fontSize: 13, fontFamily: T.mono,
            background: 'transparent', border: 'none', color: T.textSec, cursor: 'pointer',
          }}>
            Close
          </button>
        </div>
      </div>
    </div>
  );
}
