/**
 * Economy Strategy Detail — Full strategy profile with engagement.
 * RESEARCH ONLY.
 */
import { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { api, apiPost } from '../utils/api';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import usePageTitle from '../hooks/usePageTitle';
import AhaMomentPanel from '../components/AhaMomentPanel';
import ShareStrategyModal from '../components/ShareStrategyModal';
import ViralToast from '../components/ViralToast';
import { markStep, incrementStrategyViews } from '../components/OnboardingProgress';
import { SkeletonTablePage } from '../components/SkeletonUI';
import s from './EconomyStrategyPage.module.css';

const T = { bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover, border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary, green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue, amber: tokens.color.amber, purple: tokens.color.purple, mono: tokens.font.mono };

function M({ label, value, color, large }) {
  return <div className={s.metricCell}>
    <div className={large ? s.metricValueLarge : s.metricValueDefault} style={{ color: color || T.text }}>{value}</div>
    <div className={s.metricLabel}>{label}</div>
  </div>;
}

export default function EconomyStrategyPage() {
  const { strategyId } = useParams();
  const nav = useNavigate();
  usePageTitle(`Strategy: ${strategyId}`);
  const [data, setData] = useState(null);
  const [versions, setVersions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showShare, setShowShare] = useState(false);
  const [showViralToast, setShowViralToast] = useState(false);

  const fetch = useCallback(async () => {
    const [d, v] = await Promise.all([
      api(`/api/economy/strategy/${strategyId}`),
      api(`/api/economy/versions/${strategyId}`),
    ]);
    if (d) setData(d);
    if (v) setVersions(v.versions || []);
    setLoading(false);
  }, [strategyId]);

  useEffect(() => {
    fetch();
    // Track onboarding progress
    try { markStep('understand'); incrementStrategyViews(); } catch {}
  }, [fetch]);

  const doAction = async (action) => {
    await apiPost('/api/economy/action', { strategy_id: strategyId, action });
    fetch();
    // Trigger viral toast after engagement actions
    if (['follow', 'bookmark', 'favorite', 'add_watchlist'].includes(action)) {
      setShowViralToast(true);
    }
  };

  if (loading) return <SkeletonTablePage title="Strategy Detail" metricCount={4} cols={5} rows={6} />;
  if (!data) return <div className={s.errorMsg}>Strategy not found.</div>;

  const eng = data.engagement || {};

  return (
    <div className={s.container}>
      <button onClick={() => nav('/economy')} className={s.backBtn}>← Economy</button>

      <GlassPanel className={s.headerPanel}>
        <div className={s.headerRow}>
          <div>
            <h1 className={s.title}>{data.title || strategyId}</h1>
            <div className={s.subtitle}>
              {data.family} · {data.direction} · {data.publish_state}
              {data.creator_type && ` · by ${data.origin_type || data.creator_type}`}
            </div>
            {data.summary && <p className={s.summary}>{data.summary}</p>}
          </div>
          <div className={s.alphaRight}>
            <div className={s.alphaValue} style={{ color: data.alpha_score >= 0.7 ? T.green : T.text }}>{(data.alpha_score || 0).toFixed(3)}</div>
            <div className={s.alphaLabel}>Alpha Score</div>
          </div>
        </div>
      </GlassPanel>

      {/* Micro-guidance for new users */}
      <div className={s.microGuidance}>
        These metrics show how well this strategy holds up over time — not just recent performance.
      </div>

      <div className={s.metricsGrid6}>
        <GlassPanel><M label="Sharpe" value={(data.sharpe || 0).toFixed(2)} color={data.sharpe >= 1.5 ? T.green : T.text} /></GlassPanel>
        <GlassPanel><M label="PF" value={(data.profit_factor || 0).toFixed(2)} /></GlassPanel>
        <GlassPanel><M label="Reputation" value={(data.reputation_score || 0).toFixed(2)} color={data.reputation_score >= 0.7 ? T.green : T.text} /></GlassPanel>
        <GlassPanel><M label="DD" value={`${((data.max_drawdown || 0) * 100).toFixed(0)}%`} color={data.max_drawdown < -0.25 ? T.red : T.text} /></GlassPanel>
        <GlassPanel><M label="Followers" value={eng.follower_count || data.follower_count || 0} /></GlassPanel>
        <GlassPanel><M label="Rating" value={(eng.rating_avg || 0).toFixed(1)} color={T.amber} /></GlassPanel>
      </div>

      {/* Aha Moment — why this strategy stands out */}
      <AhaMomentPanel strategy={data} />

      <div className={s.detailGrid}>
        <GlassPanel>
          <h3 className={s.sectionTitle}
              ref={el => { if (el) { try { markStep('validate'); } catch {} } }}>RESEARCH QUALITY</h3>
          {[
            { l: 'Walk-Forward', v: data.walk_forward_score },
            { l: 'Regime Stability', v: data.regime_stability_score },
            { l: 'Cross-Asset', v: data.cross_asset_consistency },
          ].map(m => (
            <div key={m.l} className={s.barRow}>
              <span className={s.barLabel}>{m.l}</span>
              <div className={s.barTrack}>
                <div className={s.barFill} style={{ width: `${(m.v || 0) * 100}%` }} />
              </div>
              <span className={s.barValue}>{(m.v || 0).toFixed(2)}</span>
            </div>
          ))}
        </GlassPanel>

        <GlassPanel>
          <h3 className={s.sectionTitle}>ENGAGEMENT</h3>
          <div className={s.engagementGrid}>
            <M label="Bookmarks" value={eng.bookmark_count || 0} />
            <M label="Watchlists" value={eng.watchlist_count || 0} />
            <M label="Favorites" value={eng.favorite_count || 0} />
          </div>
        </GlassPanel>
      </div>

      {versions.length > 0 && (
        <GlassPanel className={s.versionPanel}>
          <h3 className={s.sectionTitle}>VERSION HISTORY</h3>
          {versions.map(v => (
            <div key={v.version_id} className={s.versionRow} style={{ borderBottom: `1px solid ${T.border}22` }}>
              <span className={s.versionId}>{v.version_id?.slice(0, 16)}</span>
              <span className={s.versionId} style={{ color: v.status === 'active' ? T.green : T.textSec }}>{v.status}</span>
              <span className={s.versionGen}>gen {v.generation || 0}</span>
            </div>
          ))}
        </GlassPanel>
      )}

      <div className={s.actionsRow}>
        {[
          { a: 'follow', l: 'Follow', c: T.blue },
          { a: 'bookmark', l: 'Bookmark', c: T.amber },
          { a: 'add_watchlist', l: 'Watchlist', c: T.green },
          { a: 'mark_paper_candidate', l: 'Paper Candidate', c: T.amber },
          { a: 'favorite', l: 'Favorite', c: T.purple },
        ].map(b => (
          <button key={b.a} onClick={() => doAction(b.a)} className={s.actionBtn}
            style={{ background: b.c + '18', border: `1px solid ${b.c}55`, color: b.c }}>
            {b.l}
          </button>
        ))}

        {/* Share button */}
        <button onClick={() => setShowShare(true)} className={s.actionBtn}
          style={{ background: T.blue + '18', border: `1px solid ${T.blue}55`, color: T.blue }}>
          Share
        </button>
      </div>

      {/* Share modal */}
      {showShare && <ShareStrategyModal strategy={data} onClose={() => setShowShare(false)} />}

      {/* Viral toast — triggers after engagement */}
      <ViralToast
        show={showViralToast}
        strategyTitle={data?.title || ''}
        onShare={() => setShowShare(true)}
        onCompare={() => nav('/economy')}
        onDismiss={() => setShowViralToast(false)}
      />
    </div>
  );
}
