/**
 * ViralToast — Triggers after engagement actions (bookmark/follow).
 * Suggests sharing or comparing to create viral loops.
 */
import { useState, useEffect } from 'react';
import { tokens } from '../styles/tokens';

const T = {
  surface: tokens.color.surface, border: tokens.color.border,
  text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, blue: tokens.color.blue, mono: tokens.font.mono,
};

export default function ViralToast({ show, strategyTitle, onShare, onCompare, onDismiss }) {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (show) {
      const t = setTimeout(() => setVisible(true), 800);
      return () => clearTimeout(t);
    }
    setVisible(false);
  }, [show]);

  if (!visible) return null;

  const dismiss = () => { setVisible(false); onDismiss?.(); };

  return (
    <div style={{
      position: 'fixed', bottom: 24, left: '50%', transform: 'translateX(-50%)', zIndex: 1500,
      background: T.surface, border: `1px solid ${T.blue}33`, borderRadius: 10,
      padding: '12px 18px', maxWidth: 380, boxShadow: '0 8px 24px rgba(0,0,0,0.4)',
      display: 'flex', alignItems: 'center', gap: 12,
    }}>
      <div style={{ flex: 1 }}>
        <div style={{ fontSize: 13, fontWeight: 600, fontFamily: T.mono, color: T.text, marginBottom: 4 }}>
          Want a second opinion?
        </div>
        <div style={{ fontSize: 10, color: T.textSec }}>
          Share {strategyTitle ? `"${strategyTitle}"` : 'this strategy'} or compare it against another.
        </div>
      </div>
      <div style={{ display: 'flex', gap: 8, flexShrink: 0 }}>
        <button onClick={() => { onShare?.(); dismiss(); }} style={{
          padding: '5px 10px', borderRadius: 6, fontSize: 10, fontFamily: T.mono, fontWeight: 700,
          background: T.blue + '15', border: `1px solid ${T.blue}44`, color: T.blue, cursor: 'pointer',
        }}>Share</button>
        <button onClick={() => { onCompare?.(); dismiss(); }} style={{
          padding: '5px 10px', borderRadius: 6, fontSize: 10, fontFamily: T.mono,
          background: 'transparent', border: `1px solid ${T.border}`, color: T.textSec, cursor: 'pointer',
        }}>Compare</button>
        <button onClick={dismiss} style={{ fontSize: 13, color: T.textSec, background: 'none', border: 'none', cursor: 'pointer', opacity: 0.4 }}>✕</button>
      </div>
    </div>
  );
}
